Here's a modern, data-driven MSTest test class for your `PriceCalculator`. It replaces the legacy anti-patterns with current best practices:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- CalculateTotal ---

    [TestMethod]
    [DataRow(10, 2, 0.1, 22.0, DisplayName = "Basic with 10% tax")]
    [DataRow(5, 0, 0.1, 0.0, DisplayName = "Zero quantity")]
    [DataRow(10, 1, 0.0, 10.0, DisplayName = "No tax")]
    [DataRow(0, 5, 0.2, 0.0, DisplayName = "Zero price")]
    public void CalculateTotal_ValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);
        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));
        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativePrice_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(-5m, 1, 0.1m));
        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.1)]
    [DataRow(1.1)]
    public void CalculateTotal_InvalidTaxRate_Throws(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));
        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // --- ApplyDiscount (DynamicData with ValueTuples) ---

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_ValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);
        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)>
        DiscountTestData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (80m, 100m, 0m),
    ];

    [TestMethod]
    [DataRow(-1.0)]
    [DataRow(101.0)]
    public void ApplyDiscount_InvalidPercent_Throws(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    // --- FormatPrice ---

    [TestMethod]
    [DataRow(9.99, "$", "$9.99")]
    [DataRow(0.5, "€", "€0.50")]
    [DataRow(1000, "$", "$1000.00")]
    public void FormatPrice_WithSymbol_ReturnsFormatted(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);
        Assert.AreEqual(expected, result);
    }
}
```

**Key improvements over the legacy tests:**

| Anti-pattern removed | Modern replacement |
|---|---|
| Non-sealed class | `sealed` class |
| `[TestInitialize]` for sync setup | Constructor with `readonly` field |
| `[ExpectedException]` | `Assert.ThrowsExactly<T>` + `ParamName` check |
| Swapped `Assert.AreEqual` args | `expected` first, `actual` second |
| Manual `foreach` over `object[]` | `[DynamicData]` with **ValueTuples** for type safety |
| `Assert.IsTrue(str.Contains(...))` | Specialized `Assert.AreEqual` on formatted output |
| Vague test names (`Test1`) | `Method_Scenario_Expected` naming |

> **Note:** `[DataRow]` doesn't support `decimal` literals directly, so `double` params are cast to `decimal` in the method body. For complex/decimal-heavy data, `[DynamicData]` with ValueTuples (as shown for `ApplyDiscount`) is preferred.
